 1	import * as React from 'react';
 2	import { Tooltip, TooltipPosition } from '@patternfly/react-core';
 3	import fullIcon from '../../assets/img/mtls/mtls-status-full.svg';
 4	import hollowIcon from '../../assets/img/mtls/mtls-status-partial.svg';
 5	import fullIconDark from '../../assets/img/mtls/mtls-status-full-dark.svg';
 6	import hollowIconDark from '../../assets/img/mtls/mtls-status-partial-dark.svg';
 7	import { useKialiTheme } from 'utils/ThemeUtils';
 8	import { Theme } from 'types/Common';
 9	import { MTLSIconTypes } from './NamespaceMTLSStatus';
10	
11	type MTLSIconProps = {
12	  icon: string;
13	  iconClassName: string;
14	  tooltipPosition: TooltipPosition;
15	  tooltipText: string;
16	};
17	
18	export const MTLSIcon: React.FC<MTLSIconProps> = (props: MTLSIconProps) => {
19	  const darkTheme = useKialiTheme() === Theme.DARK;
20	  const [mtlsIcon, setMtlsIcon] = React.useState('');
21	
22	  React.useEffect(() => {
23	    if (props.icon === MTLSIconTypes.LOCK_FULL) {
24	      setMtlsIcon(darkTheme ? fullIcon : fullIconDark);
25	    } else if (props.icon === MTLSIconTypes.LOCK_HOLLOW) {
26	      setMtlsIcon(darkTheme ? hollowIcon : hollowIconDark);
27	    }
28	  }, [darkTheme, props.icon]);
29	
30	  return (
31	    <Tooltip aria-label="mTLS status" position={props.tooltipPosition} enableFlip={true} content={props.tooltipText}>
32	      <img key={mtlsIcon} className={props.iconClassName} src={mtlsIcon} alt={props.tooltipPosition} />
33	    </Tooltip>
34	  );
35	};

