 1	import * as React from 'react';
 2	import { MTLSIcon } from '../MTLSIcon';
 3	import { mount } from 'enzyme';
 4	import { mountToJson } from 'enzyme-to-json';
 5	import { Tooltip, TooltipPosition } from '@patternfly/react-core';
 6	import { Provider } from 'react-redux';
 7	import { store } from 'store/ConfigStore';
 8	import { MTLSIconTypes } from '../NamespaceMTLSStatus';
 9	
10	const mockIcon = (icon: string) => {
11	  const component = (
12	    <Provider store={store}>
13	      <MTLSIcon
14	        icon={icon}
15	        iconClassName="className"
16	        tooltipText="Overlay Test"
17	        tooltipPosition={TooltipPosition.right}
18	      />
19	    </Provider>
20	  );
21	  return mount(component);
22	};
23	
24	describe('when Icon is LOCK_FULL', () => {
25	  it('MTLSIcon renders properly', () => {
26	    const mount = mockIcon(MTLSIconTypes.LOCK_FULL);
27	
28	    expect(mountToJson(mount)).toBeDefined();
29	    expect(mountToJson(mount)).toMatchSnapshot();
30	
31	    const tooltip = mount.find(Tooltip);
32	    expect(tooltip.exists()).toBeTruthy();
33	    expect(tooltip.props().position).toEqual('right');
34	    expect(tooltip.props().content).toEqual('Overlay Test');
35	
36	    const img = tooltip.find('img');
37	    expect(img.exists()).toBeTruthy();
38	    expect(img.props().className).toEqual('className');
39	    expect(img.props().src).toEqual('mtls-status-full-dark.svg');
40	  });
41	});
42	
43	describe('when Icon is LOCK_HOLLOW', () => {
44	  it('MTLSIcon renders properly', () => {
45	    const mount = mockIcon(MTLSIconTypes.LOCK_HOLLOW);
46	    const img = mount.find('img');
47	    expect(img.exists()).toBeTruthy();
48	    expect(img.props().className).toEqual('className');
49	    expect(img.props().src).toEqual('mtls-status-partial-dark.svg');
50	  });
51	});

